<template>
  <div class="main">
    <div class="content">
    
        <Nav index = '3'/>
      <div class="show_wrap">
            <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              {{itemData['医院名称']}}
            </h1>
        <div class="row height55">
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <h4 class="card_title">饼图对比</h4>
              <div class="card_show">
                <div class="pie" ref= 'mychartpie'></div>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
               <h4 class="card_title">筛选条件</h4>
              <div class="card_show"> 
                <div class="model_table">
                  <div class="col">
                    <div class="row">医院名称</div>
                    <div class="row" style='position:relative'>
                      <el-select @change='change($event)' v-model="vala" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in data"
                          :key="index"
                          :label="item['医院名称']"
                          :value="item['医院名称']">
                        </el-option>
                      </el-select>
                    </div>
                  </div>
                    <div class="col">
                    <div class="row">型号规格</div>
                    <div class="row">
                      <el-select v-model="valb" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in data"
                          :key="index"
                          :label="item['型号规格']"
                          :value="item['型号规格']">
                        </el-option>
                      </el-select>
                    </div>
                  </div>
                    <div class="col">
                    <div class="row">类型</div>
                    <div class="row">
                      <el-select v-model="valc" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in data"
                          :key="index"
                          :label="item['类型']"
                          :value="item['类型']">
                        </el-option>
                      </el-select>
                    </div>
                  </div>
                    <div class="col">
                    <div class="row">出厂编号</div>
                    <div class="row">
                    <el-select v-model="vald" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in data"
                          :key="index"
                          :label="item['出厂编号']"
                          :value="item['出厂编号']">
                        </el-option>
                      </el-select>
                    </div>
                  </div>
                    <div class="col">
                    <div class="row">生产厂家</div>
                    <div class="row">
                    <el-select v-model="vale" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in data"
                          :key="index"
                          :label="item['生产厂家']"
                          :value="item['生产厂家']">
                        </el-option>
                      </el-select>
                    </div>
                  </div>
                    <div class="col">
                    <div class="row">所在区县</div>
                    <div class="row">
                    <el-select v-model="valf" placeholder="请选择">
                        <el-option
                          v-for="(item , index) in data"
                          :key="index"
                          :label="item['医院所在区县']"
                          :value="item['医院所在区县']">
                        </el-option>
                      </el-select>
                    </div>
                  </div>

                </div>
              </div>
            </div>
        </div>
        </div>
        <div class="row height45">
            <div class="col">
              <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
                <h4 class="card_title">实时数据</h4>
                <div class="card_show">
                <div class="model_table">
                  <div class="col">
                    <div class="row">医院名称</div>
                    <div class="row">型号规格</div>
                    <div class="row">类型</div>
                    <div class="row">出厂编号</div>
                    <div class="row">生产厂家</div>
                    <div class="row">医院级别</div>
                    <div class="row">等级</div>
                    <div class="row">医院所在区县</div>
                  </div>
                  <div class="col" v-for='item in data'>
                    <div class="row">{{item['医院名称']}}</div>
                    <div class="row">{{item['型号规格']}}</div>
                    <div class="row">{{item['类型']}}</div>
                    <div class="row">{{item['出厂编号']}}</div>
                    <div class="row">{{item['生产厂家']}}</div>
                    <div class="row">{{item['医院级别']}}</div>
                    <div class="row">{{item['等级']}}</div>
                    <div class="row">{{item['医院所在区县']}}</div>
                  </div>
                </div>
                </div>
            </div>
        </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'

import Nav from './Nav.vue'

export default {
  name: 'Pie',
  components:{Nav},
  data () {
    return {
      msg: 'Welcome to Your Vue.js App',
      chart:null,
      tableData:[
        ['北京航星医院', 'DR 200' , '摄影' , '/' , '江苏鱼跃医疗', '公立','一级' ,'东城'],
        ['北京航星医院', 'AX 200' , '摄影' , '/' , '江苏鱼跃医疗', '公立','一级' ,'东城']
      ],
      data:this.gloData,
      vala:'',
      valb:'',
      valc:'',
      vald:'',
      vale:'',
      valf:'',
      itemData:null,
    }
  },
  methods: {
    change(e ){
      for(var i = 0 ; i < this.data.length ; i++){
        if(this.data[i]['医院名称'] == e){
          localStorage.setItem('index' , i)
        }
      }
    }
  },
  mounted() {
        var index = localStorage.getItem('index') ? parseInt(localStorage.getItem('index')) : 0;
        this.itemData = this.gloData[index];
        // 基于准备好的dom，初始化echarts实例
        this.chart = echarts.init(this.$refs.mychartpie);
        var option = {
            tooltip: {
                trigger: 'item',
                formatter: "{a} <br/>{b} : {c} ({d}%)"
            },
            legend: {
                orient: 'vertical',
                y: '70%',
                x: 'left',
                data: ['96.7%', '26.7%', '16.7%'],
                textStyle: {
                    color: "#fff"
                }
            },
            series: [{
                name: '访问来源',
                type: 'pie',
                radius: '75%',
                center: ['50%', '50%'],
                data: [{
                        value: 967,
                        name: '96.7%'
                    },
                    {
                        value: 267,
                        name: '26.7%'
                    },
                    {
                        value: 167,
                        name: '16.7%'
                    }
                ],
                itemStyle: {
                    emphasis: {
                        shadowBlur: 10,
                        shadowOffsetX: 0,
                        shadowColor: 'rgba(0, 0, 0, 0.5)',
                    }
                },
                label: {
                    normal: {
                        position: 'inner'
                    },
                    emphasis: {
                        show: true,
                        textStyle: {
                            fontSize: '30',
                            fontWeight: 'bold'
                        }
                    }
                },
                color: ['#20bbe9', '#f99f01', '#01b66c']
            }]
        };
        // 使用刚指定的配置项和数据显示图表。
        this.chart.setOption(option);
  },
}
</script>

<style scoped>
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}

</style>



