<template>
  <div class="main">
    <div class="content">
    

      <Nav index = '1'></Nav>
      <div class="show_wrap">
              <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              {{data["医院名称"]}}
              </h1>
        <div class="row height55">
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <h4 class="card_title">设备地址</h4>
              <div class="card_show">
                <div class="img_map">
                  <img src="../assets/map.png" alt="">
                </div>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
               <h4 class="card_title">设备信息</h4>
              <div class="card_show"> 
                <div class="model_table">
                  <div class="col" v-for='(value , key , index) in data'>
                    <div class="row">{{key}}</div>
                    <div class="row">{{value}}</div>
                  </div>
                </div>
              </div>
            </div>
        </div>
        </div>
        <div class="row height45">
            <div class="col">
              <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
               <h4 class="card_title">实时数据</h4>
              <div class="chartpost" ref = 'mychart'>

              </div>
            </div>
        </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'
import Nav from './Nav.vue'


export default {
  name: 'Index',
  components:{Nav},
  data () {
    return {
      msg: 'Welcome to Your Vue.js App',
      chart:null,
      data:null
    }
  },
  mounted() {
        var index = localStorage.getItem('index') ? parseInt(localStorage.getItem('index')) : 0;
        this.data = this.gloData[index];
        // 基于准备好的dom，初始化echarts实例
        this.chart = echarts.init(this.$refs.mychart);
        var timeArr = [];
        for (var index = 0; index < 30; index++) {
            timeArr.push(index)
        }

        var dataArr = [];

        for (var i = 0; i < 30; i++) {
            dataArr.push(Math.random() * 300);
        }

        // 指定图表的配置项和数据
        var option = {
            title: {
                text: "单位：",
                textStyle: {
                    color: "#597d97",
                    fontWeight: 100
                },
                left: 20
            },
            color: ['#3398DB'],
            tooltip: {
                trigger: 'axis',
                axisPointer: { // 坐标轴指示器，坐标轴触发有效
                    type: 'shadow' // 默认为直线，可选为：'line' | 'shadow'
                }
            },
            grid: {
                left: '3%',
                right: '4%',
                bottom: '3%',
                containLabel: true,
                axisLabel: {
                    textStyle: {
                        color: "#597d97"
                    }
                }
            },
            xAxis: [{
                type: 'category',
                data: timeArr,
                axisTick: {
                    alignWithLabel: true
                },
                axisLabel: {
                    textStyle: {
                        color: "#667e9a"
                    }
                },
                axisLine: {
                    lineStyle: {
                        color: "#063d7e"
                    }
                }
            }],
            yAxis: [{
                type: 'value',
                axisLabel: {
                    textStyle: {
                        color: "#667e9a"
                    }
                },
                axisLine: {
                    lineStyle: {
                        color: "#063d7e"
                    }
                }
            }],
            series: [{
                name: '辐射量',
                type: 'bar',
                barWidth: '60%',
                data: dataArr,
                itemStyle: {
                    normal: {
                        color: "#20d090"
                    }
                }
            }],
            legend: {
                data: ['辐射量'],
                textStyle: {
                    color: "#fff"
                }
            }
        };


        // 使用刚指定的配置项和数据显示图表。
        this.chart.setOption(option);
  },
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
</style>



