</template>

<script>

import echarts from 'echarts'
import Nav from './Nav.vue'

export default {
  name: 'Interaction',
  components:{Nav},
  data () {
    return {
      msg: 'Welcome to Your Vue.js App',
      chart:null,
      tableData:[
        ['北京航星医院', 'DR 200' , '摄影' , '/' , '江苏鱼跃医疗', '公立','一级' ,'东城'],
        ['北京航星医院', 'AX 200' , '摄影' , '/' , '江苏鱼跃医疗', '公立','一级' ,'东城']
      ],
      data:null,
    }
  },
  mounted() {
        var index = localStorage.getItem('index') ? parseInt(localStorage.getItem('index')) : 0;
        this.data = this.gloData[index];
        // 基于准备好的dom，初始化echarts实例
            // 基于准备好的dom，初始化echarts实例
            var myCharta = echarts.init(this.$refs.mycharta);

            var myChartb = echarts.init(this.$refs.mychartb);


            var myChartc = echarts.init(this.$refs.mychartc);
            var myChartd = echarts.init(this.$refs.mychartd);
            var option = {
                xAxis: {
                    type: 'category',
                    data: ['01', '02', '03', '04', '05'],
                    axisLabel: {
                        textStyle: {
                            color: "#83ecf3"
                        }
                    },
                    axisLine: {
                        lineStyle: {
                            color: "#063d7e"
                        }
                    }
                },
                yAxis: {
                    type: 'value',
                    axisLabel: {
                        textStyle: {
                            color: "#fff"
                        }
                    },
                    axisLine: {
                        lineStyle: {
                            color: "#fff"
                        }
                    }
                },
                series: [{
                    data: [820, 932, 1290, 1330, 1320],
                    type: 'line',
                    itemStyle: {
                        normal: {
                            lineStyle: {
                                color: '#87d75c'
                            }
                        }
                    },
                }]
            };


            // 使用刚指定的配置项和数据显示图表。
            myCharta.setOption(option);
            myChartb.setOption(option);
            myChartc.setOption(option);
            myChartd.setOption(option);
  },
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
